INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$In-Browser PDF Editing$q$, $q$Add text, images, checkmarks, dates, and freehand annotations to a PDF directly in the browser without installing software.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$eSignature Requests$q$, $q$Collect legally binding signatures from one or multiple signers, with defined signing order and automatic reminders.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Google Workspace & Dropbox Integration$q$, $q$Edit and sign PDF attachments directly from Gmail, Google Drive, Google Classroom, and Dropbox via a dedicated extension.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Reusable Templates$q$, $q$Convert frequently sent documents into templates that can be reused for recurring contracts and forms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$DocHub Intelligence (AI Assistant)$q$, $q$An AI-powered assistant available on paid plans that supports smart edits, enhanced document search, and suggested labels.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Fillable Form Fields$q$, $q$Insert text boxes, checkboxes, dropdowns, and date fields to turn a static PDF into a fillable form.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Team Folders & Collaboration$q$, $q$Organize documents into shared folders and invite team members, from 5 on Basic to unlimited on Site License.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Document Certification & Password Protection$q$, $q$Add password protection and formal certification to completed documents on Pro and above.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Free plan is genuinely usable for occasional PDF editing and a handful of e-signature requests per month$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Deep, native integration with Gmail and Google Drive means files never need to be downloaded and re-uploaded$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Simple, uncluttered browser-based editor with a low learning curve compared to desktop PDF suites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Per-user pricing on Basic and Pro is noticeably cheaper than DocuSign or Adobe Acrobat Sign for small teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Free and Basic plans cap monthly e-signature requests, which can be limiting for active individual users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$HIPAA compliance and Business Associate Agreements are only available on the custom-priced Site License tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Advanced PDF manipulation, such as heavy OCR workflows or complex conditional form logic, is more limited than dedicated PDF suites like Adobe Acrobat$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$The experience is primarily browser-based, without the offline-first native desktop apps some competitors offer$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Is DocHub free to use?$q$, $q$Yes. DocHub's Free plan covers basic PDF editing, self-signing, and a limited number of e-signature requests per month; paid Basic and Pro plans remove most of those caps.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Who owns DocHub?$q$, $q$DocHub is owned by airSlate, a Boston-area document workflow automation company that acquired DocHub in July 2022. airSlate also owns SignNow, pdfFiller, and US Legal Forms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Does DocHub integrate with Google Drive and Gmail?$q$, $q$Yes. DocHub has a dedicated browser extension and Google Workspace integration that lets users open, edit, and sign PDF attachments directly from Gmail and Google Drive.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Is DocHub HIPAA compliant?$q$, $q$DocHub can support HIPAA compliance with a signed Business Associate Agreement, but only on its custom-priced Site License plan, not on Free, Basic, or Pro.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$How much does DocHub Pro cost?$q$, $q$DocHub's Pro plan is billed per user and runs about $12 per user per month when billed annually, or a higher rate month-to-month, and includes unlimited e-signature requests.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$What is DocHub Intelligence?$q$, $q$DocHub Intelligence is the platform's built-in AI assistant, available on paid plans, that helps with smart edits, enhanced document search, and suggested labels.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Small Business Contract Signing$q$, $q$Freelancers and small businesses send contracts and invoices for signature and track completion status without paying for enterprise e-signature software.$q$, $q$Freelancers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Google Workspace Document Workflows$q$, $q$Teams already living in Gmail and Google Drive edit and sign PDF attachments in place, avoiding repeated downloads and uploads.$q$, $q$Teams using Google Workspace$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Recurring HR and Real Estate Paperwork$q$, $q$HR teams and real estate agents use saved templates to quickly send the same offer letters, leases, or disclosure forms for repeated signature collection.$q$, $q$HR teams and real estate agents$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Basic PDF editing and self-signing (limited monthly uses)","Up to 5 e-signature requests per month","3 folders maximum","Basic AI assistant access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Basic$q$, $q$$8/user/month (billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited PDF downloads and self-signing","Unlimited templates and folders","Up to 5 team members","Advanced PDF tools","Limited e-signature requests per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Pro$q$, $q$$12/user/month (billed annually, ~$16 month-to-month)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited PDF editing and e-signature requests","Full DocHub Intelligence AI suite","Team collaboration and bulk send","In-person signing","Document password protection and certification","30-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Site License$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Everything in Pro","Unlimited users","Volume discounts","HIPAA compliance with signed BAA","SSO","Priority support and early feature access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DocHub is a browser-based PDF editor and e-signature tool that lets people fill, annotate, and sign documents without leaving Gmail, Google Drive, or Dropbox. Founded in 2014 and acquired by airSlate in 2022, it has built its reputation on a fast, no-install editing experience aimed at individuals and small teams rather than enterprise document management.$q$, $q$Rather than requiring a file to be downloaded, edited in a desktop app, and re-uploaded, DocHub opens PDFs directly from a linked cloud storage account or email attachment and saves changes back in place, which is one of the main reasons it has become a popular Chrome Web Store and Google Workspace Marketplace tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes text and image insertion, freehand annotation, fillable form fields, and multi-signer e-signature requests with signing order and reminders. Paid plans add DocHub Intelligence, an AI assistant for smart edits, document search, and suggested labels, along with bulk sending, in-person signing, and document password protection or certification.$q$, $q$Documents are organized into shared folders, and reusable templates let teams standardize contracts or forms that get sent repeatedly, reducing the setup time for recurring paperwork.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DocHub uses a four-tier freemium model: Free (limited edits and e-signature requests), Basic (around $8/user/month annually, unlimited downloads and folders for up to 5 members), Pro (around $12/user/month annually, unlimited editing and e-signatures plus the full AI suite), and a custom-priced Site License for unlimited users, HIPAA/BAA compliance, and SSO.$q$, $q$Annual billing across all paid plans saves roughly 25% compared to month-to-month pricing, and Pro includes a 30-day free trial before payment is required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Postfix SMTP Server$q$, $q$Handles outbound and inbound mail transport, with optional LDAP-backed authentication for centralized user management.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Dovecot IMAP/POP3$q$, $q$Provides mail retrieval with Sieve filtering support and configurable per-user storage quotas.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Rspamd / SpamAssassin + ClamAV$q$, $q$Combines spam scoring engines with ClamAV antivirus scanning to filter unwanted and malicious email.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$OpenDKIM & OpenDMARC$q$, $q$Signs and validates outbound email to improve deliverability and protect against spoofing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Fail2ban Integration$q$, $q$Automatically blocks IP addresses attempting brute-force login attacks against the mail server.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Let's Encrypt Support$q$, $q$Automates TLS certificate issuance and renewal for encrypted mail transport.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$File-Based Configuration$q$, $q$All settings live in environment variables and configuration files rather than a database, making setups reproducible and version-controllable.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Docker & Kubernetes Ready$q$, $q$Deploys as a standard container via Docker Compose or Kubernetes manifests, fitting into existing infrastructure-as-code workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Completely free and open source under the permissive MIT license with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Combines a full mail stack, SMTP, IMAP, antispam, antivirus, and DKIM/DMARC, into a single maintained container$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$File-based configuration makes deployments reproducible and easy to manage with version control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Large, active community with roughly 18,600 GitHub stars and regular releases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$No built-in web admin UI or webmail client, requiring separate tools for non-technical management$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Requires solid working knowledge of DNS, TLS, and email deliverability to run reliably$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$No official managed hosting or paid support directly from the maintainers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$As with any self-hosted mail server, IP and domain reputation must be actively managed to avoid deliverability problems$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Is docker-mailserver free?$q$, $q$Yes. docker-mailserver is fully open source and free to use under the MIT license, with no paid tiers or subscriptions from the project itself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Who maintains docker-mailserver?$q$, $q$It was originally created by developer Tom Van Belle and has been maintained by a volunteer community under the docker-mailserver GitHub organization since January 2021.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Does docker-mailserver include a webmail interface?$q$, $q$No. The project focuses on the mail transport and delivery stack (SMTP/IMAP) and intentionally does not bundle a database or webmail client, leaving those to be paired in separately.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$What spam and antivirus protection does it include?$q$, $q$It supports Rspamd or SpamAssassin for spam filtering and ClamAV for antivirus scanning, along with OpenDKIM and OpenDMARC for outbound email authentication.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Can docker-mailserver run on Kubernetes?$q$, $q$Yes. Because it is a standard Docker image configured via files and environment variables, it can be deployed with Docker Compose or adapted to run on Kubernetes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$How does docker-mailserver compare to Mailcow or Mail-in-a-Box?$q$, $q$docker-mailserver is more minimal, it omits a bundled database and admin UI in favor of file-based configuration, making it lighter and more scriptable but less point-and-click than all-in-one alternatives like Mailcow.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Self-Hosted Personal Email$q$, $q$Privacy-focused individuals run their own mail server on a personal domain instead of relying on a third-party email provider.$q$, $q$Self-hosting enthusiasts and privacy-focused individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Small Business Email Infrastructure$q$, $q$Small organizations keep email on infrastructure they control for cost, compliance, or data-residency reasons.$q$, $q$Small businesses and IT administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Homelab and DevOps Environments$q$, $q$Homelab users and DevOps teams integrate a mail server into existing Docker or Kubernetes-based infrastructure alongside other self-hosted services.$q$, $q$Homelab users and DevOps engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full Postfix + Dovecot mail stack","Spam and antivirus filtering","DKIM/DMARC email authentication","Fail2ban and Let's Encrypt support","MIT license, no usage limits"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$docker-mailserver is a free, open-source mail server distributed as a single Docker image that bundles Postfix, Dovecot, anti-spam and anti-virus tooling, and DKIM/DMARC email authentication. It is configured through plain files rather than a database, which keeps deployments simple, versionable, and portable across Docker Compose and Kubernetes.$q$, $q$Originally created by developer Tom Van Belle, the project has been maintained by a volunteer community under the docker-mailserver GitHub organization since January 2021, and remains actively developed with regular releases and roughly 18,600 GitHub stars.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The stack includes Postfix for SMTP with optional LDAP authentication, Dovecot for IMAP/POP3 with Sieve filtering and quotas, and a choice of Rspamd or SpamAssassin paired with ClamAV for spam and virus filtering. OpenDKIM and OpenDMARC handle outbound authentication, Fail2ban blocks brute-force login attempts, and Let's Encrypt integration automates TLS certificates.$q$, $q$Because the project deliberately omits a bundled database or web admin UI, it is often paired with separate webmail clients or admin panels chosen by the administrator, making it a flexible building block rather than an all-in-one turnkey product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$docker-mailserver is entirely free and open source under the MIT license, with no paid tiers, subscriptions, or vendor-sold support contracts. The only real costs are the user's own server, storage, and domain infrastructure.$q$, $q$There is no official managed cloud version; organizations that want managed hosting typically pay a third-party provider separately to run the container on their behalf, while the software itself remains free to self-host.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6761ccd8-5a87-4df7-8db5-4222ccd81539', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Trackable Document Links$q$, $q$Share documents via a secure link instead of an attachment, with the ability to revoke access or swap the file after sending.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Page-by-Page Analytics$q$, $q$See how long each viewer spent on every page of a document, helping gauge real engagement and interest.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Email Verification & NDAs$q$, $q$Require viewers to verify their email address or accept a one-click NDA before accessing sensitive documents.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Dynamic Watermarking$q$, $q$Automatically stamp viewer identity and timestamp onto document pages to deter unauthorized sharing on higher tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Deal Rooms & Spaces$q$, $q$Organize related documents into branded, trackable folders for fundraising rounds or sales deals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$eSignature Requests$q$, $q$Collect signatures on shared documents without switching to a separate e-signature tool.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Team Engagement Tracking$q$, $q$See aggregated engagement data across a team's shared documents to identify the most effective sales or pitch materials.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$CRM & Storage Integrations$q$, $q$Connect with Gmail, Outlook, Salesforce, and cloud storage providers to fit into existing sales and fundraising workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Detailed, page-level analytics make it easy to see genuine viewer engagement rather than just an open/not-opened status$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Strong brand recognition and trust specifically within the startup fundraising and VC community$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Ability to revoke access or update a shared file after sending, without needing to resend a new link$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Backed by Dropbox's infrastructure and security investment since its 2021 acquisition$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Per-user pricing with minimum seat requirements on Advanced and Data Rooms plans gets expensive quickly for small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$No meaningful free plan, only a free trial, unlike some lower-cost competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Advanced features like watermarking and NDAs are locked behind the higher-priced Advanced tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Enterprise pricing is not published and requires a sales conversation, making budgeting harder to plan in advance$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Who owns DocSend?$q$, $q$DocSend is owned by Dropbox, which acquired the company for $165 million in March 2021. It continues to operate as a distinct, actively developed Dropbox product.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$How much does DocSend cost?$q$, $q$DocSend's Personal plan starts around $15 per user per month (about $10/month billed annually), with Standard around $65/month, Advanced around $250/month for a minimum of three users, and custom Enterprise pricing for larger teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Is DocSend free?$q$, $q$DocSend does not have a permanent free plan; it offers a free trial of its paid plans rather than an ongoing free tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$What is DocSend mainly used for?$q$, $q$It is most commonly used for sharing pitch decks during startup fundraising, sales proposals and sales collateral, and sensitive documents in M&A or finance data rooms.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Can DocSend track who views a document?$q$, $q$Yes. When email verification is enabled, DocSend shows the identity of each viewer along with page-by-page time spent, giving senders detailed engagement analytics.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$What are the main alternatives to DocSend?$q$, $q$Common alternatives include Papermark (an open-source competitor), PandaDoc, DocuSign Rooms, and dedicated data-room platforms like Intralinks and Ansarada.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Startup Fundraising$q$, $q$Founders share pitch decks with investors via trackable links and use page-level analytics to gauge investor interest and follow up strategically.$q$, $q$Startup founders raising venture capital$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Sales Proposal Tracking$q$, $q$Sales teams send proposals and collateral to prospects and see exactly which sections get the most attention, informing follow-up conversations.$q$, $q$B2B sales and account executive teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$M&A and Finance Data Rooms$q$, $q$Deal teams share sensitive financial and diligence documents with controlled access, watermarking, and audit trails during M&A or fundraising processes.$q$, $q$Finance, M&A, and corporate development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Personal$q$, $q$$15/user/month (~$10/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Trackable document links","Basic view analytics","Email verification","eSignature capability","Up to 100 document visits/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Standard$q$, $q$$65/user/month (~$45/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited document visits","Spaces for folder organization","Branded document viewer","Real-time team engagement tracking","Cloud storage integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Advanced$q$, $q$$250/month for 3 users (~$150/user/month billed annually); additional users ~$90/month$q$, $q$monthly or annual$q$, NULL, $q$["Document watermarking","Viewer identity verification","One-click NDAs","Unlimited deal rooms","Custom branded subdomain","50GB storage per user"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Advanced Data Rooms$q$, $q$$300/month for 3 users (~$180/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Advanced","Enhanced data room permissions","Advanced audit logs","Dedicated data room support","Higher storage limits"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["SSO/SAML integration","API access","Dedicated account manager","Custom contract terms and SLAs","Advanced security controls"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DocSend is a secure document sharing platform, now owned by Dropbox, built around trackable links instead of email attachments. Senders upload a file, share a link, and receive page-by-page analytics on how recipients engage with the document, without recipients needing to download the file or create an account.$q$, $q$It is best known in the startup fundraising world, where founders use it to share pitch decks and read investor engagement, but it is equally used by sales, finance, and deal teams that need to share sensitive materials with visibility and control.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every shared link can include access controls such as email verification, expiration dates, one-click NDAs, and dynamic watermarking, and senders can revoke access or swap the underlying file at any time. Real-time analytics show time spent per page and viewer identity, which helps sales and fundraising teams gauge genuine interest.$q$, $q$Higher tiers add Spaces for organizing documents into deal-specific folders, unlimited deal rooms, a branded document viewer, and enterprise features like SSO and API access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DocSend is billed per user across four main tiers: Personal (around $15/month, or $10/month annually), Standard (around $65/month, or $45/month annually), Advanced (around $250/month for a minimum of 3 users, additional users around $90/month), and a custom-priced Enterprise tier for larger deployments.$q$, $q$Annual billing saves roughly 30 to 35% compared to month-to-month pricing across all tiers, and Advanced and Data Rooms plans require a minimum of three paid users.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Automatic Metadata Extraction$q$, $q$Uses OCR and natural language processing to suggest correspondents, tags, and document dates with minimal manual input.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$OCR for Scanned Documents$q$, $q$Extracts text from scanned images and PDFs using Tesseract, making handwritten and printed paperwork fully searchable.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Full-Text Search$q$, $q$All extracted document text is indexed and searchable through the web interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Shared Collectives$q$, $q$Multiple users, such as family members, share the same document pool while keeping their own individual accounts and settings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$REST/HTTP API$q$, $q$Every function is exposed through an API, enabling automation and integration with other self-hosted tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Native Android App$q$, $q$A dedicated Android app allows convenient scanning and uploading of documents directly from a phone or tablet.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Command-Line Interface$q$, $q$A CLI tool supports scripted uploads and batch document processing workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Self-Hosted Data Control$q$, $q$All documents and data are stored on infrastructure the user controls, with no third-party cloud dependency.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Completely free and open source under the AGPLv3 license with no feature limits or paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Machine-learning-assisted tagging and metadata extraction reduce manual filing effort over time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Multi-user 'collective' model is well suited to families or small groups sharing one document pool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Full REST API, Android app, and CLI make it easy to automate and integrate into existing self-hosted setups$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Requires self-hosting expertise; there is no official managed cloud version from the project$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Smaller community and ecosystem than the more widely adopted Paperless-ngx$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$OCR and NLP-based suggestions require correction and training over time to reach high accuracy$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$No corporate support contract or SLA is available since it is a volunteer-maintained project$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Is Docspell free?$q$, $q$Yes. Docspell is completely free and open source under the AGPLv3 license, with no paid tiers, subscriptions, or usage limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Who maintains Docspell?$q$, $q$Docspell is created and primarily maintained by developer Eike Kettner along with a community of open-source contributors, with no corporate backing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Can Docspell run on my own server?$q$, $q$Yes, Docspell is designed to be self-hosted, typically via Docker Compose or a native package, so all documents and data stay on infrastructure the user controls.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Does Docspell support OCR?$q$, $q$Yes. It uses Tesseract OCR to extract text from scanned images and PDFs, making them fully searchable.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$How is Docspell different from Paperless-ngx?$q$, $q$Docspell places more emphasis on machine-learning-assisted metadata suggestion and supports a multi-user 'collective' model for households or small groups, whereas Paperless-ngx has a larger community and more mainstream single-archive adoption.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Does Docspell have a mobile app?$q$, $q$Yes, Docspell offers a native Android app for capturing and uploading documents, alongside its mobile-friendly web interface.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Household Paperwork Organization$q$, $q$Families digitize receipts, invoices, contracts, and tax documents into a shared, searchable archive that every household member can access under their own account.$q$, $q$Families and households$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Privacy-Focused Personal Archiving$q$, $q$Privacy-conscious individuals scan and organize personal documents without uploading sensitive files to a third-party SaaS service.$q$, $q$Privacy-focused individuals and self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Small Team Document Sharing$q$, $q$Small companies or groups use a shared collective to manage business documents such as invoices and contracts across a small team.$q$, $q$Small businesses and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["OCR and automatic metadata extraction","Full-text search","Shared collectives for multi-user access","REST API, Android app, and CLI","AGPLv3 license, no usage limits"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Docspell is a free, open-source, self-hosted document organizer that helps individuals, families, and small groups digitize and organize documents from scanners, email, and other sources with minimal manual filing. It focuses on automatically extracting metadata like correspondent, date, and tags rather than requiring rigid manual folder structures.$q$, $q$The project is maintained by developer Eike Kettner and a community of open-source contributors, distributed under the AGPLv3 license, with no corporate parent, headquarters, or funding behind it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Documents are OCR'd via Tesseract and analyzed with Stanford CoreNLP-based natural language processing to suggest correspondents, tags, and dates, with the system learning from confirmed metadata over time. All content becomes full-text searchable through the web interface.$q$, $q$Docspell organizes access around shared 'collectives' so multiple users, such as members of a household, can work with the same document pool under their own individual accounts, and everything is accessible via a REST/HTTP API, a mobile-friendly web app, a native Android app, and a command-line interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Docspell is entirely free and open source under the AGPLv3 license, with no subscription tiers, feature gating, or user limits imposed by the project itself.$q$, $q$There is no official managed cloud hosting offered by the Docspell project; users self-host via Docker Compose, native packages, or building from source, with the only costs being their own server and storage infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e57311ae-2760-4595-acff-07a9102a6a78', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Real-Time Appointment Booking$q$, $q$Patients search doctors by specialty and location and book, reschedule, or cancel appointments online in real time, for free.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Telemedicine Consultations$q$, $q$Integrated video consultations let patients see a doctor remotely, with a separate professional subscription for providers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Electronic Health Records (Doctolib Médecin)$q$, $q$Practice management and EHR software for healthcare professionals, including patient records and billing integration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$National Insurance Card Reader Integration$q$, $q$Hardware and software integration for processing French national health insurance (Carte Vitale) at the point of care.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Automated Reminders$q$, $q$Automatic appointment reminders reduce no-show rates for healthcare practices.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Mobile Apps (iOS and Android)$q$, $q$Native mobile apps let patients search, book, and manage appointments from their phone.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Multi-Practitioner Practice Coordination$q$, $q$Tools for clinics and hospital groups to coordinate scheduling and records across multiple practitioners and locations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Waiting List Management$q$, $q$Practices can manage patient waiting lists and fill last-minute cancellations more efficiently.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Appointment booking is completely free for patients, with a simple and widely recognized booking experience$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Large installed base of roughly 80 million patient accounts across France, Germany, Italy, and the Netherlands makes it easy for practices to be discovered$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Combines booking, EHR, telemedicine, and insurance processing into one integrated professional platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Well-funded and continuing to invest in expansion, reducing near-term risk of the platform being discontinued$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Professional pricing is layered across multiple separate subscriptions (booking, telemedicine, EHR, card reader), which can add up$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$France represents the large majority of revenue, so feature depth and support quality can vary in newer markets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Enterprise and multi-practitioner pricing is not published and requires a custom sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$As a French-market-first product, some workflows are most mature for the French healthcare system before other markets$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Is Doctolib free for patients?$q$, $q$Yes. Booking a medical appointment as a patient through Doctolib's website or app is free; the paid subscriptions apply to the healthcare professionals and clinics using the platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$How much does Doctolib cost for doctors?$q$, $q$The core Doctolib Pro booking subscription is roughly €139/month, with telemedicine access around €79/month, the Doctolib Médecin EHR product around €1,600/year, and a card-reader device around €29/month, all billed separately.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Who founded Doctolib?$q$, $q$Doctolib was founded in 2013 in Paris by Stanislas Niox-Chateau, Ivan Schneider, Steve Abou Rjeily, and Jessy Bernal.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$What countries does Doctolib operate in?$q$, $q$Doctolib primarily operates in France, Germany, Italy, and the Netherlands, with an announced expansion into the United Kingdom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Does Doctolib offer telemedicine?$q$, $q$Yes, Doctolib offers integrated video telemedicine consultations, available to healthcare professionals through a separate paid subscription.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$How much is Doctolib worth?$q$, $q$Doctolib reached a valuation of $6.4 billion following a $549 million Series F funding round in March 2022, making it one of Europe's most valuable healthtech companies.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Booking a Doctor's Appointment$q$, $q$Patients search for available doctors by specialty and location and book an appointment online in a few clicks, without calling the practice.$q$, $q$Patients in France, Germany, Italy, and the Netherlands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Independent Practice Management$q$, $q$Solo practitioners and small clinics use Doctolib Médecin to manage scheduling, patient records, and insurance billing in one system.$q$, $q$Independent doctors and small clinics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Telemedicine Consultations$q$, $q$Healthcare providers offer remote video consultations to patients who cannot visit in person, integrated with the same booking and records system.$q$, $q$Healthcare professionals offering remote care$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Patient Booking$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Search doctors by specialty and location","Real-time appointment booking","Automated reminders","Telemedicine appointment booking","iOS and Android apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Doctolib Pro (Booking Subscription)$q$, $q$~€139/month$q$, $q$monthly$q$, NULL, $q$["Online calendar and appointment management","Patient communication tools","Waiting list management","Free trial, no credit card required"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Telemedicine Add-On$q$, $q$~€79/month$q$, $q$monthly$q$, NULL, $q$["Integrated video consultations","Remote patient care tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Doctolib Médecin (EHR)$q$, $q$~€1,600/year$q$, $q$annual$q$, NULL, $q$["Electronic health records","Billing integration","Practice management tools"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Card Reader Add-On$q$, $q$~€29/month$q$, $q$monthly$q$, NULL, $q$["National insurance card reader hardware/software integration"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$Enterprise (Clinics & Hospital Groups)$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Multi-practitioner coordination","Custom modules and integrations","Dedicated account support"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Doctolib is a French healthtech platform that lets patients book medical appointments online for free while selling practice management, electronic health record, and telemedicine software to the healthcare professionals on the other side of the marketplace. It is one of Europe's largest healthtech companies, operating primarily in France, Germany, Italy, and the Netherlands.$q$, $q$Founded in Paris in 2013, Doctolib grew from a simple appointment-booking tool into a full healthcare operations platform, gaining significant additional visibility when it was used to coordinate France's COVID-19 vaccination booking system.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$For patients, Doctolib offers real-time calendar search, online booking, automated reminders, and integrated video telemedicine consultations through its web and mobile apps. For healthcare professionals, Doctolib Médecin adds electronic health records, billing integration, and card-reader hardware support for French national insurance processing.$q$, $q$The platform also supports waiting-list management, recurring patient communications, and, for larger clinics and hospital groups, coordination tools across multiple practitioners and locations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The patient-facing booking experience is completely free. Healthcare professionals pay for the platform: the core Doctolib Pro subscription runs around €139/month, telemedicine access is roughly €79/month, the electronic health record product (Doctolib Médecin) costs about €1,600/year, and a card-reader device adds around €29/month.$q$, $q$Larger clinics, hospital groups, and institutional customers negotiate custom pricing based on practitioner count and modules needed, and a free trial without requiring a credit card is available for evaluating the professional product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3824531-7fee-4eb7-9d43-f3de065cb703', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Open-Source Codebase (AGPL)$q$, $q$The entire signing interface, workflow engine, and audit trail are published as open-source code, auditable by anyone.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Self-Hosted Deployment Option$q$, $q$Organizations can run the full Documenso application on their own infrastructure for free, keeping complete control of signed documents and data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Multi-Recipient Signing Workflows$q$, $q$Send documents to multiple recipients with configurable signing order and up to 10 recipients per document on the free tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$API Access & Embedded Signing$q$, $q$A typed API (via tRPC) lets developers automate document creation and embed a white-labeled signing experience into their own product on higher tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Audit Trail$q$, $q$Every signing action is logged in a verifiable audit trail, important for legal and compliance purposes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Modern PDF Handling$q$, $q$PDF rendering and manipulation is handled through pdf.js, @cantoo/pdf-lib, and the project's own @libpdf/core library.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Team Collaboration$q$, $q$Teams plans support multiple included users with per-additional-user pricing for growing organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Stripe-Powered Billing$q$, $q$Hosted subscription billing runs through Stripe, supporting standard monthly and discounted annual billing cycles.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Fully open-source and AGPL-licensed, allowing complete code audit and free self-hosting, unlike closed-source competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Hosted and self-hosted versions run the identical codebase, so there is no stripped-down 'community edition'$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Free hosted plan is genuinely usable for casual signing needs with no credit card required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Modern, well-documented tech stack makes it approachable for developers who want to extend or customize it$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Free plan is capped at 5 documents per month, which will not suit anyone with regular signing volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$As a 2023-founded startup, it has a shorter enterprise track record than incumbents like DocuSign$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Self-hosting requires technical setup and ongoing maintenance that a purely SaaS competitor would not require$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Team pricing jumps meaningfully between the Teams and Platform tiers for organizations that outgrow 5 users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Is Documenso free?$q$, $q$Yes. Documenso offers a hosted Free plan with 5 documents per month and up to 10 recipients per document, and the full application can also be self-hosted for free under the AGPL license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Can I self-host Documenso?$q$, $q$Yes. Documenso's entire codebase, including the signing workflow, API, and audit trail, is open source under AGPL, so it can be deployed on your own infrastructure at no licensing cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Who founded Documenso?$q$, $q$Documenso was founded in 2023 by Timur Ercan, based in Germany, and has raised approximately $2.2 million in early-stage funding.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$How much does Documenso cost?$q$, $q$Paid hosted plans start at $25/month for Individual (billed annually), $40/month for Teams (5 users included, billed annually), and $250/month for Platform (unlimited users, billed annually), with custom Enterprise pricing available.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Is Documenso legally binding?$q$, $q$Documenso provides electronic signatures with an audit trail intended to support legally binding signing workflows, similar in concept to DocuSign, though specific legal requirements vary by jurisdiction and document type.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$How is Documenso different from DocuSign?$q$, $q$Documenso is open source and self-hostable under the AGPL license, letting organizations audit the code or run it on their own infrastructure, whereas DocuSign is a closed-source, fully proprietary SaaS platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Self-Hosted Compliance-Sensitive Signing$q$, $q$Organizations with strict data-residency or compliance requirements self-host Documenso to keep signed documents and audit data entirely within their own infrastructure.$q$, $q$Regulated industries and privacy-focused organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Embedded Signing in a Product$q$, $q$Software companies use Documenso's API to embed a white-labeled document-signing experience directly inside their own application.$q$, $q$Developers and SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Low-Cost Individual and Team Signing$q$, $q$Freelancers and small teams use the hosted Free or Individual plan as a lower-cost alternative to DocuSign for everyday contract signing.$q$, $q$Freelancers and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["5 documents per month","Up to 10 recipients per document","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Individual$q$, $q$$25/month ($300 billed yearly)$q$, $q$annual$q$, NULL, $q$["Unlimited documents","API access for personal use","Email support","Premium profile name"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Teams$q$, $q$$40/month ($480 billed yearly) for 5 users; +$8/month per additional user$q$, $q$annual$q$, NULL, $q$["Unlimited documents","API access for automation","Embedded signing","Email support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Platform$q$, $q$$250/month ($3,000 billed yearly)$q$, $q$annual$q$, NULL, $q$["Unlimited users and documents","Unlimited API access","White-labeled embedded signing","Slack-based integration support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Advanced compliance and licensing","Tailored support","Cloud or self-hosted deployment"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$Self-Hosted (Open Source)$q$, $q$Free (paid licensing option available)$q$, $q$n/a$q$, NULL, $q$["Full AGPL-licensed codebase","Unlimited signatures when self-hosted","Optional paid support and compliance licensing"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Documenso is an open-source e-signature platform marketed as 'The Open Source DocuSign Alternative,' offering both a hosted freemium SaaS product and a fully self-hostable, AGPL-licensed codebase that anyone can inspect or deploy on their own infrastructure.$q$, $q$Founded in Germany in 2023 by Timur Ercan and backed by roughly $2.2 million in early funding, the project has grown to around 14,000 GitHub stars and ships regular releases on a modern TypeScript stack.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Documenso supports document upload, multi-recipient signing workflows, an audit trail, and API access for automating signature requests, all built on React Router v7, Hono, PostgreSQL/Prisma, and tRPC. PDF handling is powered by pdf.js and the project's own @libpdf/core library.$q$, $q$Because the hosted and self-hosted versions share the same open-source codebase, teams can start on the hosted product and migrate to self-hosting later, or vice versa, without losing feature parity.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Documenso offers a Free hosted plan (5 documents/month, up to 10 recipients each), Individual at $25/month billed annually, Teams at $40/month billed annually for 5 users ($8/month per additional user), and Platform at $250/month billed annually for unlimited users and documents.$q$, $q$The full application can also be self-hosted for free under the AGPL license, with a paid self-hosted licensing option and a custom-priced Enterprise tier available for organizations needing dedicated support and compliance guarantees.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4da77cfa-32ce-403c-8b98-4e1620167573', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Versioned Knowledge Base Articles$q$, $q$Maintain multiple versions of documentation for different product releases or audiences with full version control.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Eddy AI Assistant$q$, $q$AI-powered search, writing assistance, and content suggestions built directly into the documentation editor.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Automatic Translation$q$, $q$Translate knowledge base content into more than 50 languages using Eddy AI's translation capabilities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Video/Audio-to-Text Conversion$q$, $q$Convert screen recordings, video, or audio into written documentation, extended by the acquisition of Floik.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Multiple Workspaces$q$, $q$Manage several documentation projects or product lines within a single Document360 account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Role-Based Team Accounts$q$, $q$Assign writer and reviewer roles with structured content approval workflows before publishing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$SSO & Enterprise Security$q$, $q$Single sign-on and configurable access controls support enterprise security and compliance requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Mixed Public/Private Knowledge Bases$q$, $q$Configure some content as publicly accessible while restricting other sections to logged-in or authenticated users.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Purpose-built for structured, versioned documentation rather than being a general-purpose wiki adapted for the job$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Strong AI feature set with Eddy AI covering search, writing assistance, and translation into 50+ languages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Supports both public customer-facing help centers and private internal knowledge bases in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Backed by an established company (Kovai.co) with a multi-year track record and a second flagship product$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$No published pricing and no self-serve free tier since the November 2024 change, requiring a sales conversation for every plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Custom, factor-based pricing makes it harder to budget or compare costs against competitors upfront$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Sales-led positioning may be a mismatch for very early-stage startups wanting a quick self-serve setup$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Heavier feature set and versioning model can be more than small teams with simple documentation needs actually require$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Does Document360 have a free plan?$q$, $q$No. Document360 discontinued its free tier in November 2024 and now uses fully custom, quote-based pricing, though a 14-day free trial is still available.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$How much does Document360 cost?$q$, $q$Document360 does not publish fixed prices. Cost depends on the number of workspaces, languages, team account seats, SSO needs, privacy model, and AI Premium Suite usage, determined through a sales quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Who owns Document360?$q$, $q$Document360 is built and owned by Kovai.co, a UK-headquartered enterprise software company with a major engineering office in Coimbatore, India, founded around 2009 by Saravana Kumar.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$What is Eddy AI?$q$, $q$Eddy AI is Document360's built-in AI assistant suite, providing AI-powered knowledge base search, writing assistance, translation into 50+ languages, and video/audio-to-text conversion.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$What is Document360 used for?$q$, $q$It is used to build customer-facing help centers, internal knowledge bases and wikis, and API documentation, with support for content versioning across product releases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$What are Document360's main competitors?$q$, $q$Common alternatives include Confluence, GitBook, Zendesk Guide, Helpjuice, and Docsie, all of which compete in the knowledge base and documentation software space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Customer-Facing Help Center$q$, $q$Software companies publish a public, searchable knowledge base to help customers self-serve answers and reduce support ticket volume.$q$, $q$Customer support and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Internal Team Wiki$q$, $q$Organizations use a private, access-controlled knowledge base to document internal processes, onboarding, and institutional knowledge.$q$, $q$Internal operations and HR teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$API and Developer Documentation$q$, $q$Engineering teams publish versioned API references and technical documentation that stays in sync with product releases.$q$, $q$Engineering and developer relations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Professional$q$, $q$Custom (quote-based)$q$, $q$annual$q$, NULL, $q$["Versioned knowledge base","Team accounts for writers/reviewers","Basic Eddy AI features","14-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Business$q$, $q$Custom (quote-based)$q$, $q$annual$q$, NULL, $q$["Multiple workspaces","Expanded Eddy AI suite","SSO and advanced security","Mixed public/private knowledge base"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Enterprise$q$, $q$Custom (quote-based)$q$, $q$annual$q$, NULL, $q$["Full Eddy AI Premium Suite","Advanced compliance and security","Dedicated support","Custom workspace and language allocations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Document360 is a knowledge base and documentation platform used to build public help centers, internal wikis, and API documentation, built by Kovai.co, a UK-headquartered enterprise software company with major operations in Coimbatore, India.$q$, $q$Founded in December 2017, Document360 was developed as Kovai.co's second major SaaS product after BizTalk360, and has grown into a dedicated documentation platform with a strong focus on AI-assisted writing, search, and translation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Content is organized into categories and articles with full version control, supporting multiple documentation versions across product releases. The Eddy AI suite adds AI-powered search, automatic translation into more than 50 languages, and conversion of video or audio into written documentation.$q$, $q$The platform supports multiple workspaces within one account, role-based team accounts for writers and reviewers, SSO for enterprise security, and configurable privacy models mixing public and restricted content.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Document360 removed its free tier in November 2024 and now uses fully custom, quote-based pricing across three named plans: Professional, Business, and Enterprise. Cost is determined by workspaces, languages, team account seats, SSO/security needs, privacy model, and AI Premium Suite usage.$q$, $q$There is no published starting price; prospective customers complete a questionnaire and speak with sales for a tailored quote, though a 14-day free trial remains available to evaluate the product before purchase.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Self-Hosted Single Binary$q$, $q$Documize compiles to a single Go executable that runs on Linux, Windows, or macOS with minimal dependencies beyond a database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Documents, Wikis & Templates$q$, $q$Build documentation from reusable sections and templates, organized into spaces for different teams or projects.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Approval Workflows$q$, $q$Route content through review and approval steps before it is published to the wider organization.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Built-In Analytics$q$, $q$See how documentation is actually being read and used across the organization to identify gaps or outdated content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Flat Annual Pricing$q$, $q$Cost is a flat $900/year for up to 100 users or $1,800/year for unlimited users, rather than per-seat billing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Database Flexibility$q$, $q$Supports PostgreSQL, Microsoft SQL Server, or MySQL-compatible databases for content storage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Open-Source Community Edition$q$, $q$The Community+ edition is open source under AGPLv3 and free for the first five users of an installation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Confluence-Style Spaces$q$, $q$Organizes content into spaces similar to Confluence, making migration and onboarding familiar for teams switching over.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Free for up to 5 users with the full feature set, not a stripped-down trial version$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Flat annual pricing ($900/100 users, $1,800/unlimited) is highly predictable and often cheaper than per-seat SaaS wikis at scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Deploys as a single Go binary, making self-hosting simpler than heavier Java-based enterprise wiki platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Keeps all organizational knowledge on infrastructure the organization controls, useful for compliance and data sovereignty$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Requires self-hosting and database setup, unlike fully managed cloud competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Smaller ecosystem, plugin marketplace, and community size compared to Atlassian Confluence$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$No official large-scale managed cloud offering directly from Documize itself$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$As a small independent team's product, long-term roadmap pace may be slower than venture-backed competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Is Documize free?$q$, $q$Yes, for up to 5 users. The Community+ edition is free with the full feature set for the first five users on an installation; beyond that, flat annual pricing applies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$How much does Documize cost beyond 5 users?$q$, $q$Pricing is a flat $900 per year for up to 100 users, or $1,800 per year for unlimited users, with no feature differences between the two paid tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Is Documize open source?$q$, $q$Yes, the Community+ edition is open source, maintained on GitHub under the documize/community repository, and licensed under the GNU AGPLv3.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Who created Documize?$q$, $q$Documize Inc. was founded in 2016 in San Francisco by Harvey Kandola, who previously founded enterprise software company Countersoft.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$What platforms does Documize run on?$q$, $q$Documize compiles to a single binary and runs on Linux, Windows, or macOS, requiring only a supported database such as PostgreSQL, SQL Server, or MySQL.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$How does Documize compare to Confluence?$q$, $q$Documize is positioned as a lighter, simpler self-hosted alternative to Confluence, deploying as a single Go binary with flat annual pricing rather than Confluence's per-user SaaS or data-center licensing model.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Self-Hosted Company Wiki$q$, $q$Organizations replace or avoid Confluence by self-hosting Documize as their internal wiki and documentation hub, keeping content on their own infrastructure.$q$, $q$IT teams and small-to-midsize organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Approval-Based Documentation Publishing$q$, $q$Teams that need content reviewed before publication use Documize's approval workflows to control what gets published to the broader organization.$q$, $q$Compliance-conscious teams and regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Cost-Predictable Knowledge Base at Scale$q$, $q$Growing organizations use Documize's flat annual pricing to scale up to 100 or more users without incremental per-seat cost increases.$q$, $q$Budget-conscious IT and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Community+ (Free)$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Free for up to 5 users","Full feature set included","Self-hosted single binary","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Up to 100 Users$q$, $q$$900/year$q$, $q$annual$q$, NULL, $q$["All Community+ features","Support for up to 100 users","Approval workflows and analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$Unlimited Users$q$, $q$$1,800/year$q$, $q$annual$q$, NULL, $q$["All Community+ features","Unlimited users on a single installation","Approval workflows and analytics"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Documize is a self-hosted knowledge management and wiki platform positioned as a lighter-weight, on-premises-friendly alternative to Atlassian Confluence, combining documents, wikis, templates, and approval workflows in a single application.$q$, $q$Founded in 2016 in San Francisco by Harvey Kandola, previously the founder of enterprise software company Countersoft, Documize was built with an enterprise-software mindset around self-contained, easy-to-deploy software rather than a cloud-only SaaS model.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Content is organized into spaces containing documents built from reusable sections and templates, with approval workflows to review content before publishing and built-in analytics on how documentation is actually being read.$q$, $q$The application compiles to a single Go binary that runs on Linux, Windows, or macOS, requiring only a supported database (PostgreSQL, SQL Server, or MySQL), which keeps deployment simple compared to heavier enterprise wiki platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Documize is free for the first five users on an installation with the full feature set included. Beyond five users, pricing is a flat $900 per year for up to 100 users, or $1,800 per year for unlimited users, with no feature gating between tiers.$q$, $q$Because it is self-hosted, there are no additional cloud hosting fees from Documize itself; the only ongoing cost beyond the license is the organization's own server and database infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dc626839-0d04-4df9-9c03-63658e2f415a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
